// Bridge the trigger gap: the two ensures `forall|i: int|` clauses use
// disjoint triggers (`post1_self_.page_array@[i]` vs `post2_self_.page_array@[i]`),
// so z3 never lines them up on the same `i`. Re-assert each so they enter the
// proof context with their own triggers and become available for instantiation.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise equality of the two page_array views: case-split on whether i hits
// the modified index. Off-index both posts equal pre; at the index every field
// is pinned by the ensures (addr/state/is_io_page/rev_pointer/ref_count/
// owning_container/mappings to pre, io_mappings to io_mapping), so the two
// Pages are field-wise equal. Note that `io_mappings` has type
// `Ghost<Set<(IOid, VAddr)>>`, so the comparison is against `io_mapping`
// (the `Ghost`-wrapped parameter), not `io_mapping@`.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        assert(post1_self_.page_array@[i].addr =~= pre_self_.page_array@[index as int].addr);
        assert(post2_self_.page_array@[i].addr =~= pre_self_.page_array@[index as int].addr);
        assert(post1_self_.page_array@[i].state =~= pre_self_.page_array@[index as int].state);
        assert(post2_self_.page_array@[i].state =~= pre_self_.page_array@[index as int].state);
        assert(post1_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[index as int].is_io_page);
        assert(post2_self_.page_array@[i].is_io_page =~= pre_self_.page_array@[index as int].is_io_page);
        assert(post1_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer);
        assert(post2_self_.page_array@[i].rev_pointer =~= pre_self_.page_array@[index as int].rev_pointer);
        assert(post1_self_.page_array@[i].ref_count =~= pre_self_.page_array@[index as int].ref_count);
        assert(post2_self_.page_array@[i].ref_count =~= pre_self_.page_array@[index as int].ref_count);
        assert(post1_self_.page_array@[i].owning_container =~= pre_self_.page_array@[index as int].owning_container);
        assert(post2_self_.page_array@[i].owning_container =~= pre_self_.page_array@[index as int].owning_container);
        assert(post1_self_.page_array@[i].mappings =~= pre_self_.page_array@[index as int].mappings);
        assert(post2_self_.page_array@[i].mappings =~= pre_self_.page_array@[index as int].mappings);
        assert(post1_self_.page_array@[i].io_mappings =~= io_mapping);
        assert(post2_self_.page_array@[i].io_mappings =~= io_mapping);
    } else {
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Sequence extensionality lifts pointwise Page equality to view equality.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
